use std::collections::HashMap;
use std::sync::Arc;

struct ConfigBlock {
    name: String,
    data: Vec<u8>,
}

fn load_configs() -> HashMap<String, Arc<ConfigBlock>> {
    let mut map = HashMap::new();

    let config1 = ConfigBlock {
        name: "global.conf".to_string(),
        data: vec![0xde, 0xad, 0xbe, 0xef],
    };
    map.insert(config1.name.clone(), Arc::new(config1));

    let config2 = ConfigBlock {
        name: "local.conf".to_string(),
        data: vec![0xca, 0xfe, 0xba, 0xbe],
    };
    map.insert(config2.name.clone(), Arc::new(config2));

    map
}

fn main() {
    let configs = load_configs();

    if let Some(arc_config) = configs.get("global.conf") {
        println!("Successfully accessed config: {}", arc_config.name);
        // The use of Arc ensures that the data pointed to remains valid 
        // as long as any part of the program holds a reference to it.
    }

    let configs_clone = configs.clone();

    if let Some(arc_config) = configs_clone.get("local.conf") {
        println!("Safely accessed config: {}", arc_config.name);
    }
}

use std::fmt::Debug;

trait Processable {
    fn calculate_checksum(&self) -> u32;
}

struct TemperatureSensor { data: Vec<f32> }
impl Processable for TemperatureSensor {
    fn calculate_checksum(&self) -> u32 {
        self.data.iter().fold(0, |acc, &val| (acc + val.to_bits() as u32)) * 31
    }
}

struct PressureSensor { readings: &'static [i32] }
impl Processable for PressureSensor {
    fn calculate_checksum(&self) -> u32 {
        self.readings.iter().map(|&x| x as u32).sum()
    }
}

fn process_data_stream<T: Processable + Debug>(item: &T) -> u32 {
    item.calculate_checksum()
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let temp = TemperatureSensor { data: vec![20.5, 21.1, 19.8] };
    let press = PressureSensor { readings: &[100, 101, 99] };

    println!("Processing temperature data...");
    let temp_checksum = process_data_stream(&temp);
    println!("Temperature Checksum: {}", temp_checksum);

    println!("Processing pressure data...");
    let press_checksum = process_data_stream(&press);
    println!("Pressure Checksum: {}", press_checksum);

    Ok(())
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};

struct ScanResult {
    is_safe: bool,
    scan_id: u32,
}

struct VirusScanner {
    results: HashMap<u32, ScanResult>,
}

impl VirusScanner {
    fn new() -> Self {
        VirusScanner { results: HashMap::new() }
    }

    fn scan_file(scan_id: u32, file_path: &str) -> io::Result<ScanResult> {
        let mut file = File::open(file_path)?;
        let mut buffer = Vec::new();
        file.read_to_end(&mut buffer)?;

        if buffer.len() < 10 {
            return Ok(ScanResult { is_safe: false, scan_id });
        }

        let result = ScanResult { is_safe: true, scan_id };
        Ok(result)
    }
}

fn handle_upload(file_path: &str, scanner: &mut VirusScanner) -> io::Result<()> {
    println!("Starting upload process for: {}", file_path);
    let current_scan_id = 42;

    match VirusScanner::scan_file(current_scan_id, file_path) {
        Ok(result) => {
            if result.is_safe {
                println!("File {} is clean and ready to save.", file_path);
                scanner.results.insert(current_scan_id, result);
                Ok(()) 
            } else {
                eprintln!("ALERT: File {} failed virus scan (ID {}). Upload blocked.", file_path, current_scan_id);
                Err(io::Error::new(io::ErrorKind::InvalidData, "Virus detected"))
            }
        },
        Err(e) => {
            eprintln!("Failed to open or process file: {}", e);
            Err(e)
        }
    }
}

fn main() -> io::Result<()> {
    let temp_safe = "temp_safe.bin";
    let temp_virus = "temp_virus.bin";

    std::fs::write(temp_safe, &[1, 2, 3, 4, 5]);
    std::fs::write(temp_virus, &[]);

    let mut scanner = VirusScanner::new();

    handle_upload(temp_safe, &mut scanner)?;
    println!("nUpload handling complete. Total scans recorded: {}", scanner.results.len());

    std::fs::remove_file(temp_safe)?; 
    std::fs::remove_file(temp_virus)?; 
    Ok(())
}

use std::error::Error;

struct DataProcessor<'a> {
    data: &'a str,
}
impl<'a> DataProcessor<'a> {
    fn new(data: &'a str) -> Self {
        DataProcessor { data }
    }

    fn process_with_filter<F>(self, filter: F) -> Result<String, Box<dyn Error>>
where
    F: Fn(&str) -> bool + 'static
{
        let mut results = Vec::new();
        for line in self.data.lines() {
            if (|| -> bool {
                // This closure captures the filter logic and applies it to the current line
                filter(line)
            })() {
                results.push(line);
            }
        }
        Ok(results.join(","))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let csv_data = "id,name,statusn1,Alice,activen2,Bob,inactiven3,Charlie,active";

    let processor = DataProcessor::new(csv_data);

    // The filter logic must satisfy the lifetime requirements of process_with_filter
    let is_active_filter = |line: &str| -> bool {
        line.contains("active")
    };

    let result = processor.process_with_filter(is_active_filter);

    match result {
        Ok(s) => println!("Processed Data:n{}", s),
        Err(e) => eprintln!("Error processing data: {}", e),
    }
    Ok(())
}

use std::fmt::Write;

struct DeviceContext<'a> {
    read_pointer: *const u32,
    write_pointer: *mut u32,
    data_lifetime: &'a [u8],
}

impl<'a> DeviceContext<'a> {
    fn new(read_ptr: *const u32, write_ptr: *mut u32, data: &'a [u8]) -> Self {
        DeviceContext {
            read_pointer: read_ptr,
            write_pointer: write_ptr,
            data_lifetime: data,
        }
    }

    fn process_registers(&self) -> Result<String, &'static str> {
        unsafe {
            let raw_read = *self.read_pointer;
            let mut buffer = [0u8; 16];

            if self.data_lifetime.len() < 4 {
                return Err("Insufficient data block length for processing.");
            }

            buffer[0] = (raw_read & 0xFF) as u8;
            for i in 1..4 {
                let offset = i * 4;
                if offset + 3 >= self.data_lifetime.len() { 
                    return Err("Data buffer overrun during read simulation.");
                }
                buffer[i] = (self.data_lifetime[offset] & 0xFF) as u8;
            }

            let mut output = String::new();
            write!(&mut output, "ADC Read: 0x{:X}, Processed Block Start: {:02X}{:02X}{:02X}{:02X}", 
                raw_read, buffer[0], buffer[1], buffer[2], buffer[3]).unwrap();
            Ok(output) 
        }
    }
}

fn main() {
    let adc_reg: u32 = 0xDEADBEEF;
    let data_block: [u8; 20] = [0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77, 0x88, 0x99, 0xAA, 0xBB, 0xCC, 0xDD, 0xEE, 0xFF, 0x00, 0x12, 0x34, 0x56, 0x78];
    let write_ptr: *mut u32 = &mut 0;

    let context = unsafe { DeviceContext::new(adc_reg as *const u32, write_ptr, &data_block) };
    match context.process_registers() {
        Ok(s) => println!("Success: {}", s),
        Err(e) => eprintln!("Failure: {}", e),
    }
}
